    count = 0
    while n:
        count += n & 1
        n >>= 1
    return count

def hamming_weight(n: int) -> int:
    count = 0
    while n:
        n &= n - 1  # clear the lowest set bit
        count += 1
    return count

function hammingWeight(n) {
    let count = 0;
    while (n !== 0) {
        n &= n - 1;
        count++;
    }
    return count;
}
